        return { pass: false, score: 0, reason: "Output is empty or not a string" };
    }

    try {
        JSON.parse(output);
        return { pass: true, score: 1, reason: "Valid JSON" };
    } catch (err) {

        const preview = output.slice(0, 200).replace(/\n/g, "\\n");
        return {
            pass: false,
            score: 0,
            reason: `Response is not valid JSON: ${err.message}. Preview: "${preview}"`,
        };
    }

let parsed;
    try {
        parsed = JSON.parse(output);
    } catch {
        return { pass: false, score: 0, reason: "Not valid JSON — cannot check required fields" };
    }

    const errors = [];


    if (!("actions" in parsed)) {
        errors.push("missing field: actions");
    } else if (!Array.isArray(parsed.actions)) {
        errors.push(`actions must be an array, got ${typeof parsed.actions}`);
    }


    if (!("thread_updates" in parsed)) {
        errors.push("missing field: thread_updates");
    } else if (parsed.thread_updates !== null && !Array.isArray(parsed.thread_updates)) {
        errors.push(`thread_updates must be an array or null, got ${typeof parsed.thread_updates}`);
    }


    const triggerType = context?.vars?.trigger_type ?? "email_received";
    if (triggerType === "email_received") {
        if (!("email_analysis" in parsed)) {
            errors.push("missing field: email_analysis (required for email_received trigger)");
        } else if (parsed.email_analysis !== null && typeof parsed.email_analysis !== "object") {
            errors.push(`email_analysis must be an object or null, got ${typeof parsed.email_analysis}`);
        }


        if (parsed.email_analysis && typeof parsed.email_analysis === "object") {
            const analysis = parsed.email_analysis;
            const requiredAnalysisFields = ["summary", "intent", "urgency", "entities"];
            const missingAnalysis = requiredAnalysisFields.filter(f => !(f in analysis));
            if (missingAnalysis.length > 0) {
                errors.push(`email_analysis missing fields: ${missingAnalysis.join(", ")}`);
            }

            const validUrgencies = ["low", "normal", "high"];
            if (analysis.urgency && !validUrgencies.includes(analysis.urgency)) {
                errors.push(`email_analysis.urgency must be low|normal|high, got "${analysis.urgency}"`);
            }

            if ("entities" in analysis && !Array.isArray(analysis.entities)) {
                errors.push(`email_analysis.entities must be an array, got ${typeof analysis.entities}`);
            }
        }
    }


    if (Array.isArray(parsed.actions)) {
        for (let i = 0; i < parsed.actions.length; i++) {
            const action = parsed.actions[i];
            if (!action.tool) errors.push(`actions[${i}] missing tool`);
            if (!action.params || typeof action.params !== "object") {
                errors.push(`actions[${i}] missing or invalid params`);
            }
        }
    }

    if (errors.length > 0) {
        return { pass: false, score: 0, reason: errors.join("; ") };
    }

    return { pass: true, score: 1, reason: "All required fields present" };

let parsed;
    try {
        parsed = JSON.parse(output);
    } catch {
        return { pass: false, score: 0, reason: "Not valid JSON" };
    }

    const analysis = parsed.email_analysis;
    if (!analysis) {

        const triggerType = context?.vars?.trigger_type ?? "email_received";
        if (triggerType !== "email_received") return { pass: true, score: 1, reason: "Not an email trigger" };
        return { pass: false, score: 0, reason: "email_analysis missing on email_received trigger" };
    }

    const urgency = analysis.urgency;
    const emailType = (context?.vars?.email_type ?? "").toLowerCase();
    const expectedUrgency = context?.vars?.expected_urgency;

    const validUrgencies = ["low", "normal", "high"];
    if (!validUrgencies.includes(urgency)) {
        return { pass: false, score: 0, reason: `Invalid urgency value: "${urgency}". Must be low|normal|high` };
    }


    const neverHighTypes = ["receipt", "confirmation", "newsletter", "shipping", "spam", "account_setup"];
    if (neverHighTypes.includes(emailType) && urgency === "high") {
        return {
            pass: false,
            score: 0,
            reason: `${emailType} emails must not be high urgency (got: high). The system prompt says confirmations and receipts are expected events.`,
        };
    }


    if (emailType === "security_alert" && urgency === "low") {
        return {
            pass: false,
            score: 0,
            reason: `security_alert must not be low urgency. Security events should be normal or high.`,
        };
    }


    if (emailType === "action_request" && urgency === "low") {
        return {
            pass: false,
            score: 0,
            reason: `action_request emails must not be low urgency. Someone is waiting for a response.`,
        };
    }

    if (emailType === "deadline" && urgency === "low") {
        return {
            pass: false,
            score: 0,
            reason: `deadline emails must not be low urgency. Deadlines within 48 hours require attention.`,
        };
    }


    if (expectedUrgency && urgency !== expectedUrgency) {
        return {
            pass: false,
            score: 0.5,
            reason: `Expected urgency "${expectedUrgency}" but got "${urgency}" for ${emailType} email`,
        };
    }

    return { pass: true, score: 1, reason: "Urgency check passed" };

